import axios from "axios";

const API = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:5000/api",
  timeout: 10000, // 10s timeout for slow Nepal connections
});

API.interceptors.request.use((config) => {
  const token = localStorage.getItem("token");
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

// Graceful offline error handling
API.interceptors.response.use(
  (response) => response,
  (error) => {
    if (!navigator.onLine || error.code === "ECONNABORTED" || error.message === "Network Error") {
      // Tag as offline error so UI can handle gracefully
      error.isOffline = true;
    }
    return Promise.reject(error);
  }
);

export default API;
